module RefModule(
    clk,
    data,
    ce,
    a,
    q);parameter DATA_WIDTH = 8;
parameter ADDR_WIDTH = 1;
parameter DEPTH = 2;

input clk;
input [DATA_WIDTH-1:0] data;
input ce;
input [ADDR_WIDTH-1:0] a;
output [DATA_WIDTH-1:0] q;

reg[DATA_WIDTH-1:0] SRL_SIG [0:DEPTH-1];
integer obf_i;

always @ (posedge clk)
    begin
        if (ce)
        begin
            for (obf_i=0;obf_i<DEPTH-1;obf_i=obf_i+1)
                SRL_SIG[obf_i+1] <= SRL_SIG[obf_i];
            SRL_SIG[0] <= data;
        end
    end

assign q = SRL_SIG[a];

endmodule
